import { createClient } from '@/lib/supabase/server';
import { Book, Video, FileText, Activity, Clock, ArrowRight, Mic2, Languages, Sparkles } from 'lucide-react';
import Link from 'next/link';

export const metadata = {
  title: 'Admin Dashboard | Yoga Wisdom Portal',
};

export default async function AdminDashboard() {
  const supabase = await createClient();

  // Fetch counts
  const { count: booksCount } = await supabase.from('books').select('*', { count: 'exact', head: true });
  const { count: videosCount } = await supabase.from('videos').select('*', { count: 'exact', head: true });
  const { count: journalsCount } = await supabase.from('journals').select('*', { count: 'exact', head: true });
  const { count: podcastsCount } = await supabase.from('podcasts').select('*', { count: 'exact', head: true });
  const { count: translationsCount } = await supabase.from('translations').select('*', { count: 'exact', head: true });

  // Fetch recent content
  const { data: recentBooks } = await supabase
    .from('books')
    .select('id, title, created_at, status')
    .order('created_at', { ascending: false })
    .limit(3);

  const { data: recentVideos } = await supabase
    .from('videos')
    .select('id, title, created_at, status')
    .order('created_at', { ascending: false })
    .limit(3);

  const { data: recentJournals } = await supabase
    .from('journals')
    .select('id, title, created_at, status')
    .order('created_at', { ascending: false })
    .limit(3);

  const allRecent = [
    ...(recentBooks?.map(b => ({ ...b, type: 'Book' })) || []),
    ...(recentVideos?.map(v => ({ ...v, type: 'Video' })) || []),
    ...(recentJournals?.map(j => ({ ...j, type: 'Journal' })) || []),
  ].sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())
   .slice(0, 5);

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-1000">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-5xl font-bold font-heading text-white mb-3 tracking-tight">
            Dashboard <span className="text-saffron italic font-serif">Overview</span>
          </h1>
          <p className="text-white/50 font-medium italic">A holistic view of your spiritual content ecosystem.</p>
        </div>
        <div className="px-5 py-2.5 bg-white/5 border border-white/10 rounded-2xl flex items-center gap-3 text-[10px] font-black tracking-widest text-white/40 backdrop-blur-xl shadow-2xl">
          <div className="relative">
            <div className="absolute inset-0 bg-saffron/40 blur-sm rounded-full animate-pulse" />
            <Clock size={14} className="text-saffron relative z-10" />
          </div>
          LAST UPDATED: {new Date().toLocaleTimeString()}
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
        <StatCard 
          title="Sacred Texts" 
          value={booksCount || 0} 
          icon={<Book size={24} />} 
          color="saffron" 
          href="/admin/books"
          description="Total books archived"
        />
        <StatCard 
          title="Video Wisdom" 
          value={videosCount || 0} 
          icon={<Video size={24} />} 
          color="forest" 
          href="/admin/videos"
          description="Visual teachings curated"
        />
        <StatCard 
          title="Dharma Journals" 
          value={journalsCount || 0} 
          icon={<FileText size={24} />} 
          color="saffron" 
          href="/admin/journals"
          description="Monthly publications"
        />
        <StatCard 
          title="Total Assets" 
          value={(booksCount || 0) + (videosCount || 0) + (journalsCount || 0)} 
          icon={<Sparkles size={24} />} 
          color="forest" 
          href="#"
          description="Across all categories"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Recent Activity */}
        <div className="lg:col-span-2 glass-card overflow-hidden group border border-white/5 shadow-2xl rounded-[2.5rem] bg-white/[0.02] backdrop-blur-3xl">
          <div className="px-10 py-8 border-b border-white/10 flex items-center justify-between bg-white/[0.03]">
            <div className="flex items-center gap-4">
              <div className="w-2 h-8 bg-saffron rounded-full shadow-[0_0_15px_rgba(245,158,11,0.5)]" />
              <h3 className="text-2xl font-bold font-heading text-white tracking-tight">
                Recent <span className="text-white/40">Activity</span>
              </h3>
            </div>
            <Link href="/admin/books" className="group/link flex items-center gap-3 px-5 py-2.5 rounded-2xl bg-white/5 border border-white/10 text-xs font-bold text-saffron hover:bg-saffron hover:text-forest transition-all duration-500 shadow-xl">
              Explorer <ArrowRight size={16} className="group-hover/link:translate-x-1 transition-transform" />
            </Link>
          </div>
          
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-white/[0.01] text-white/30 text-[10px] uppercase tracking-[0.25em] font-black">
                  <th className="px-10 py-6">Wisdom Title</th>
                  <th className="px-10 py-6">Resource</th>
                  <th className="px-10 py-6">Status</th>
                  <th className="px-10 py-6 text-right">Added On</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/5">
                {allRecent.length > 0 ? (
                  allRecent.map((item) => (
                    <tr key={item.id} className="hover:bg-white/[0.04] transition-all duration-300 group/row">
                      <td className="px-10 py-7 font-bold text-white group-hover/row:text-saffron transition-colors text-lg tracking-tight italic">
                        {item.title}
                      </td>
                      <td className="px-10 py-7">
                        <span className={`inline-flex items-center gap-2 px-3.5 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-wider border ${
                          item.type === 'Book' ? 'bg-saffron/10 text-saffron border-saffron/20 shadow-[0_0_15px_rgba(245,158,11,0.1)]' :
                          item.type === 'Video' ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20 shadow-[0_0_15px_rgba(16,185,129,0.1)]' :
                          'bg-sky-500/10 text-sky-400 border-sky-500/20 shadow-[0_0_15px_rgba(14,165,233,0.1)]'
                        }`}>
                          {item.type === 'Book' ? <Book size={12} /> : item.type === 'Video' ? <Video size={12} /> : <FileText size={12} />}
                          {item.type}
                        </span>
                      </td>
                      <td className="px-10 py-7">
                        <span className={`flex items-center gap-3 text-[10px] font-black uppercase tracking-widest ${
                          item.status === 'published' ? 'text-emerald-400' : 'text-saffron'
                        }`}>
                          <span className={`w-2 h-2 rounded-full ${
                            item.status === 'published' ? 'bg-emerald-400 shadow-[0_0_12px_rgba(52,211,153,0.6)]' : 'bg-saffron shadow-[0_0_12px_rgba(245,158,11,0.6)]'
                          }`} />
                          {item.status}
                        </span>
                      </td>
                      <td className="px-10 py-7 text-right text-xs text-white/30 font-medium italic font-serif">
                        {new Date(item.created_at).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan={4} className="px-10 py-32 text-center">
                      <div className="flex flex-col items-center max-w-xs mx-auto">
                        <div className="relative mb-8">
                          <div className="absolute inset-0 bg-saffron/20 blur-3xl rounded-full" />
                          <div className="relative w-20 h-20 bg-white/5 rounded-3xl flex items-center justify-center border border-white/10 backdrop-blur-xl">
                            <Clock size={32} className="text-white/20" />
                          </div>
                        </div>
                        <p className="text-xl font-bold text-white mb-2 italic">Waiting for Wisdom</p>
                        <p className="text-sm text-white/40 leading-relaxed">Your content archive is currently quiet. Begin by sharing new teachings.</p>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>

        {/* Quick Stats Sidebar */}
        <div className="space-y-8">
          <div className="glass-card p-10 border border-white/5 shadow-2xl rounded-[2.5rem] bg-white/[0.02] backdrop-blur-3xl group">
            <h4 className="text-[10px] font-black uppercase tracking-[0.3em] text-white/30 mb-8 flex items-center gap-3">
              <Activity size={14} className="text-saffron" />
              Portal Health
            </h4>
            
            <div className="space-y-10">
              <div className="space-y-4">
                <div className="flex justify-between text-xs font-bold uppercase tracking-wider">
                  <span className="text-white/60">Audio Archives</span>
                  <span className="text-saffron">{podcastsCount || 0}</span>
                </div>
                <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
                  <div className="h-full bg-saffron w-[45%] rounded-full shadow-[0_0_10px_rgba(245,158,11,0.3)] group-hover:w-[55%] transition-all duration-1000" />
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between text-xs font-bold uppercase tracking-wider">
                  <span className="text-white/60">Translations</span>
                  <span className="text-emerald-400">{translationsCount || 0}</span>
                </div>
                <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
                  <div className="h-full bg-emerald-400 w-[65%] rounded-full shadow-[0_0_10px_rgba(52,211,153,0.3)] group-hover:w-[75%] transition-all duration-1000" />
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between text-xs font-bold uppercase tracking-wider">
                  <span className="text-white/60">System Logs</span>
                  <span className="text-sky-400">Stable</span>
                </div>
                <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
                  <div className="h-full bg-sky-400 w-full rounded-full shadow-[0_0_10px_rgba(14,165,233,0.3)] transition-all duration-1000" />
                </div>
              </div>
            </div>

            <div className="mt-12 pt-10 border-t border-white/5">
              <p className="text-[10px] font-medium text-white/20 italic leading-relaxed">
                The portal is currently operating within optimal parameters. All automated AI summarization and translation services are active.
              </p>
            </div>
          </div>

          <Link href="/admin/podcasts" className="block glass-card p-8 border border-saffron/10 bg-saffron/5 rounded-[2rem] group hover:bg-saffron transition-all duration-500 relative overflow-hidden">
            <div className="absolute -right-4 -bottom-4 opacity-5 group-hover:opacity-10 transition-opacity">
              <Mic2 size={120} />
            </div>
            <div className="relative z-10 flex items-center justify-between">
              <div>
                <p className="text-[10px] font-black uppercase tracking-widest text-saffron group-hover:text-forest mb-2 transition-colors">Managed Podcasts</p>
                <p className="text-xl font-bold text-white group-hover:text-forest transition-colors italic">Voice of Wisdom</p>
              </div>
              <div className="w-12 h-12 rounded-2xl bg-white/5 flex items-center justify-center border border-white/10 group-hover:bg-forest group-hover:border-forest transition-all">
                <Mic2 size={24} className="text-saffron group-hover:text-white transition-colors" />
              </div>
            </div>
          </Link>
        </div>
      </div>
    </div>
  );
}

function StatCard({ title, value, icon, color, href, description }: { title: string, value: number, icon: React.ReactNode, color: 'saffron' | 'forest', href: string, description: string }) {
  return (
    <Link href={href} className="glass-card p-8 flex flex-col group hover:translate-y-[-8px] transition-all duration-500 border border-white/5 bg-white/[0.03] backdrop-blur-3xl rounded-[2.5rem] shadow-2xl relative overflow-hidden">
      <div className={`absolute top-0 right-0 w-32 h-32 bg-${color === 'saffron' ? 'saffron' : 'forest'}/5 blur-[80px] -mr-16 -mt-16 group-hover:bg-${color === 'saffron' ? 'saffron' : 'forest'}/10 transition-all`} />
      
      <div className="flex items-center justify-between mb-8 relative z-10">
        <div className={`p-4 rounded-2xl ${
          color === 'saffron' ? 'bg-saffron/10 text-saffron' : 'bg-emerald-500/10 text-emerald-400'
        } group-hover:scale-110 transition-transform duration-700 shadow-xl border border-white/5`}>
          {icon}
        </div>
        <div className="text-[10px] font-black text-white/20 uppercase tracking-[0.2em]">{title}</div>
      </div>
      
      <div className="flex items-end justify-between relative z-10">
        <div>
          <p className="text-5xl font-bold text-white font-heading mb-2 tracking-tighter tabular-nums">{value}</p>
          <p className="text-[10px] font-bold text-white/30 uppercase tracking-widest italic">{description}</p>
        </div>
        <div className="flex flex-col gap-1.5 items-end opacity-0 group-hover:opacity-100 transition-all duration-500 translate-y-2 group-hover:translate-y-0">
          <ArrowRight size={20} className={color === 'saffron' ? 'text-saffron' : 'text-emerald-400'} />
        </div>
      </div>
      
      <div className="absolute bottom-0 left-0 w-full h-1 bg-white/[0.02]">
        <div className={`h-full ${color === 'saffron' ? 'bg-saffron' : 'bg-emerald-400'} w-0 group-hover:w-full transition-all duration-1000 shadow-[0_0_15px_${color === 'saffron' ? 'rgba(245,158,11,0.5)' : 'rgba(16,185,129,0.5)'}]`} />
      </div>
    </Link>
  );
}

